const parsed = $('Parse Webhook Input').first().json;
const ai = $input.first().json;
const generated = ai.message?.content || ai.text || ai.output || '';
if (!parsed.caption && !generated.trim()) {
  throw new Error('AI caption generation returned empty text. Check OpenAI credential and quota.');
}
return [{
  json: {
    ...parsed,
    caption: (parsed.caption || generated).trim(),
    captionSource: parsed.caption ? 'provided' : 'ai-generated'
  }
}];

const content = $('Merge Caption Branches').first().json;
const input = $input.first();
const binary = input.binary;

if (!binary) {
  throw new Error('No image binary available. Provide image_url, image_base64, or enable AI image generation.');
}

const binaryKey = Object.keys(binary).find((k) => binary[k]?.data) || 'data';
const bin = binary[binaryKey];
if (!bin?.data) {
  throw new Error('Image binary is empty.');
}

let imageContentType = bin.mimeType || 'application/octet-stream';
const fileName = bin.fileName || 'linkedin-post.jpg';

if (!imageContentType || imageContentType === 'application/octet-stream') {
  const ext = (fileName.split('.').pop() || 'jpg').toLowerCase();
  const map = { jpg: 'image/jpeg', jpeg: 'image/jpeg', png: 'image/png', gif: 'image/gif', webp: 'image/webp' };
  imageContentType = map[ext] || 'image/jpeg';
}

const linkedinAccepted = ['image/jpeg', 'image/png'];
const imageFormatWarning = linkedinAccepted.includes(imageContentType)
  ? null
  : `LinkedIn accepts JPEG/PNG only. Detected ${imageContentType}. Add a conversion step or override to image/jpeg.`;

const personId = (content.personId || '').trim();
if (!personId || personId === 'YOUR_PERSON_ID') {
  throw new Error('Set LINKEDIN_PERSON_ID in docker-compose/.env or the Configuration node.');
}

return [{
  json: {
    ...content,
    personUrn: `urn:li:person:${personId}`,
    imageFileName: fileName,
    imageContentType,
    imageFormatWarning,
    imageSource: content.imageUrl ? 'url' : 'ai-generated',
    linkedinApiVersion: content.linkedinApiVersion || '202502',
  },
  binary: { data: bin },
}];

const prepared = $('Prepare LinkedIn Payload').first();
const init = $input.first();
const value = init.json.value || init.json.body?.value || init.json;
const uploadUrl = value?.uploadUrl;
const imageUrn = value?.image;

if (!uploadUrl || !imageUrn) {
  throw new Error(`LinkedIn init upload failed: ${JSON.stringify(init.json).slice(0, 500)}`);
}

return [{
  json: {
    ...prepared.json,
    uploadUrl,
    imageUrn,
  },
  binary: prepared.binary,
}];

const merged = $('Merge Upload Data').first().json;
const post = $input.first();
const headers = post.json.headers || {};
const postUrn = headers['x-restli-id'] || headers['X-Restli-Id'] || null;

if (!postUrn) {
  throw new Error(`LinkedIn create post succeeded but no post URN in response headers: ${JSON.stringify(post.json).slice(0, 500)}`);
}

return [{
  json: {
    success: true,
    dryRun: false,
    postUrn,
    shareUrl: `https://www.linkedin.com/feed/update/${encodeURIComponent(postUrn)}/`,
    caption: merged.caption,
    captionSource: merged.captionSource,
    imageSource: merged.imageSource,
    imageContentType: merged.imageContentType,
    mediaTitle: merged.mediaTitle,
    linkedinApiVersion: merged.linkedinApiVersion,
    api: `linkedin-rest-v${merged.linkedinApiVersion || '202502'}`,
  },
}];

const item = $input.first();
const j = item.json || {};
const executionError = j.error || j;
const message =
  executionError.message ||
  executionError.description ||
  j.message ||
  (typeof executionError === 'string' ? executionError : null) ||
  'Workflow execution failed';
const failedNode =
  j.$node?.name ||
  j.node ||
  item.pairedItem?.source?.previousNode ||
  'unknown';
return [{
  json: {
    success: false,
    error: String(message).slice(0, 1000),
    failedNode: String(failedNode),
    hint: 'See docs/troubleshooting.md — verify LINKEDIN_PERSON_ID, OAuth credentials, and LINKEDIN_API_VERSION.',
    docs: 'https://github.com/Ai-assistant-KIRA/n8n-ai-linkedin-poster/blob/main/docs/troubleshooting.md',
  },
}];
